class Solution:
    def countVowelSubstrings(self, word):
        vowels = set('aeiou')
        n = len(word)
        count = 0
        for i in range(n):
            seen = set()
            for j in range(i, n):
                c = word[j]
                if c not in vowels:
                    break
                seen.add(c)
                if len(seen) == 5:
                    count += 1
        return count

