var countVowelSubstrings = function(word) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const n = word.length;
    let count = 0;
    for (let i = 0; i < n; i++) {
        const seen = new Set();
        for (let j = i; j < n; j++) {
            const c = word[j];
            if (!vowels.has(c)) break;
            seen.add(c);
            if (seen.size === 5) count++;
        }
    }
    return count;
};
